 45→void ULFPGameInstance::TransitionToBattle(const FString& BattleLevelName)
 46→{
 47→	if (bIsTransitioning) return;
 48→	bIsTransitioning = true;
 49→
 50→	FString LevelName = BattleLevelName.IsEmpty() ? DefaultBattleLevelName : BattleLevelName;
 51→	UE_LOG(LogTemp, Log, TEXT("切换到战斗关卡: %s"), *LevelName);
 52→
 53→	// 淡出到黑
 54→	UWorld* World = GetWorld();
 55→	if (World)
 56→	{
 57→		APlayerController* PC = World->GetFirstPlayerController();
 58→		if (PC && PC->PlayerCameraManager)
 59→		{
 60→			PC->PlayerCameraManager->StartCameraFade(0.f, 1.f, TransitionFadeDuration, FLinearColor::Black, false, true);
 61→		}
 62→
 63→		// 延迟后加载关卡
 64→		FTimerHandle TimerHandle;
 65→		FString CapturedLevelName = LevelName;
 66→		World->GetTimerManager().SetTimer(TimerHandle, [this, CapturedLevelName]()
 67→		{
 68→			bIsTransitioning = false;
 69→			UGameplayStatics::OpenLevel(this, FName(*CapturedLevelName));
 70→		}, TransitionFadeDuration, false);
 71→	}
 72→	else
 73→	{
 74→		bIsTransitioning = false;
 75→		UGameplayStatics::OpenLevel(this, FName(*LevelName));
 76→	}
 77→}
